body:
The following test fails, but passes with `-fno-merge-cond-motion`.  Note adding the commented-out display fixes it, as disables the bad motion from happening.

@gezalore might you take a look?

```
// Based on ivtest's pr540.v by Steve Williams.
module t;
   bit simple_fail, loop_fail, fork_fail, tlp_fail, tfk_fail;
   integer loop_cntr, tlp_cntr;
   reg fred, abort;

   initial begin
      #1;
      loop_fail = 0;
      fork_fail = 0;
      tlp_fail = 0;
      tfk_fail = 0;
      fred = 0;
      abort = 1;
      #4;
      fred = 1;
      #4;
      if (loop_fail) $error("***** block with loop disable FAILED *****");
      if (fork_fail) $error("***** forked block disable FAILED *****");
      if (tlp_fail) $error("***** task with loop disable FAILED *****");
      if (tfk_fail) $error("***** task with forked block disable FAILED ****\n");
      $write("*-* All Finished *-*\n");
      $finish(0);
   end

   // more complex: block disable inside for-loop
   initial begin
      #2;
      begin: configloop
         for (loop_cntr = 0; loop_cntr < 3; loop_cntr=loop_cntr+1) begin
            $display("time: %0t loop", $time);
            wait (fred);
            $display("time: %0t gotfred", $time);
            if (abort) begin
               disable configloop;
            end
            // Adding this makes MergeCond not merge, and it will pass
            // $display("time: %0t lf", $time);
            loop_fail = 1;
         end
      end // configloop block
      if (loop_fail) $display("\n\ttime: %0t, loop_cntr: %0d",$time,loop_cntr);
   end

endmodule
```

